namespace sv_283b8ee9cb7e46f398a82060ca7ea1f0.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — in Blazor Server each circuit (user) gets its own instance.
/// Holds current theme + accent color and notifies subscribers on change.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _mode = ThemeMode.System;
    private string _accentColor = "#0d6efd"; // Bootstrap primary blue

    public ThemeMode Mode
    {
        get => _mode;
        set
        {
            if (_mode == value) return;
            _mode = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Fired whenever Mode or AccentColor changes.
    /// Interactive components subscribe to this to call StateHasChanged().
    /// </summary>
    public event Action? OnThemeChanged;

    /// <summary>
    /// Apply multiple changes atomically (single notification).
    /// </summary>
    public void Apply(ThemeMode mode, string accentColor)
    {
        bool changed = _mode != mode || _accentColor != accentColor;
        _mode = mode;
        _accentColor = accentColor;
        if (changed) NotifyChanged();
    }

    private void NotifyChanged() => OnThemeChanged?.Invoke();
}

// Called from Blazor interactive components via JS interop to apply
// theme attributes on the <body> element (which lives in static App.razor).
export function applyTheme(mode, accentColor) {
    document.body.setAttribute("data-theme", mode.toLowerCase());
    document.documentElement.style.setProperty("--accent-color", accentColor);
}

