@* Interactive island — rendered inside the static MainLayout header.
   Because it has its own @rendermode, it runs in a SignalR circuit
   and can subscribe to ThemeService events + call StateHasChanged(). *@
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService Theme
@inject IJSRuntime JS

<span class="theme-indicator" style="color: @Theme.AccentColor;" title="Current theme">
    @ThemeIcon @Theme.Mode
</span>

@code {
    private IJSObjectReference? _module;

    private string ThemeIcon => Theme.Mode switch
    {
        Services.ThemeMode.Light  => "☀️",
        Services.ThemeMode.Dark   => "🌙",
        _                        => "💻"
    };

    protected override void OnInitialized()
    {
        Theme.OnThemeChanged += OnThemeChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/theme-interop.js");
            await ApplyThemeToDocument();
        }
    }

    private async void OnThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            StateHasChanged();
            await ApplyThemeToDocument();
        });
    }

    private async Task ApplyThemeToDocument()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync(
                "applyTheme", Theme.Mode.ToString(), Theme.AccentColor);
        }
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= OnThemeChanged;
    }
}

@* Interactive island — sits in the static sidebar.
   Lets the user cycle through Light → Dark → System. *@
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService Theme

<div class="nav-item px-3 mt-3">
    <button class="btn btn-sm btn-outline-light w-100" @onclick="CycleTheme">
        @ThemeIcon @Theme.Mode
    </button>
</div>

@code {
    private string ThemeIcon => Theme.Mode switch
    {
        Services.ThemeMode.Light  => "☀️",
        Services.ThemeMode.Dark   => "🌙",
        _                        => "💻"
    };

    protected override void OnInitialized()
    {
        Theme.OnThemeChanged += OnThemeChanged;
    }

    private void CycleTheme()
    {
        Theme.Mode = Theme.Mode switch
        {
            Services.ThemeMode.Light  => Services.ThemeMode.Dark,
            Services.ThemeMode.Dark   => Services.ThemeMode.System,
            _                        => Services.ThemeMode.Light
        };
    }

    private async void OnThemeChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= OnThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService Theme

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@Theme.Mode"
                    @onchange="OnModeChanged">
                @foreach (var mode in Enum.GetValues<Services.ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@Theme.AccentColor"
                       @onchange="OnAccentChanged" />
                <code>@Theme.AccentColor</code>
            </div>
        </div>

        <p class="text-muted small mb-0">
            Changes apply immediately across all pages and components.
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        Theme.OnThemeChanged += OnThemeChanged;
    }

    private void OnModeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Services.ThemeMode>(e.Value?.ToString(), out var mode))
        {
            Theme.Mode = mode;
        }
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        Theme.AccentColor = e.Value?.ToString() ?? Theme.AccentColor;
    }

    private async void OnThemeChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Theme.OnThemeChanged -= OnThemeChanged;
    }
}

